/**
 * Data assembly for the photographer homepage ("Darkroom" design).
 *
 * Reads live rows from D1 when available and enriches them with true image
 * dimensions from lib/data/photoManifest.json (generated by
 * scripts/build-photo-manifest.mjs — EXIF-orientation corrected, plus
 * white-matte detection for the squares wall).
 *
 * When D1 is not reachable (local `next dev`, build machines) the manifest
 * itself is used as the row source, so the page always renders with real
 * content.
 */

import manifest from './photoManifest.json'
import { normalizePhotoKey, toPublicPath } from '../photoUtils'

const CAT_ZH = {
  HK: '香港',
  City: '城市',
  Travel: '旅途',
  Portrait: '人像',
  Emotion: '情绪',
  Lover: '恋人',
  Wedding: '婚礼',
  Nature: '自然',
  Ghibli: '吉卜力',
  Phone: '随手',
}

// INDEX overlay order — people first (portraits are the main business).
const CAT_ORDER = ['Portrait', 'Emotion', 'Lover', 'Wedding', 'HK', 'City', 'Travel', 'Nature', 'Ghibli', 'Phone']

// Hand-picked hero portraits — the photographer's own banner curation.
const HERO_PANELS = [
  { p: '/photography/banner/2.jpg', w: 1344, h: 1680 },
  { p: '/photography/banner/1.jpg', w: 1343, h: 1680 },
  { p: '/photography/banner/3.jpg', w: 1344, h: 1680 },
  { p: '/photography/banner/5.jpg', w: 1344, h: 1680 },
]
// banner/4 is the only horizontal banner pick — it closes the film strip.
const HERO_WIDE = { p: '/photography/banner/4.jpg', w: 1640, h: 1093, cat: 'Lover' }

/**
 * Frames curated by eye from contact sheets of every category's top photos.
 * Resolved by filename so upstream re-sorting can't break them; anything
 * missing falls back to the top of its category pool (white mattes excluded —
 * those belong to the wall).
 */
const STRIP_PICKS = [
  ['Portrait', 'DSC00641.webp'],                              // chin on hand, smiling
  ['Portrait', 'DSC00656.webp'],                              // through the glass reflection
  ['Portrait', '0E6305BE-35AD-4370-B512-BEE2AE5827D4.webp'],  // writing by the window
  ['Emotion', '2016-10-22 11.25.26.jpg'],                     // rain, car headlights
  ['Emotion', '39A4D206-DF64-4D13-B713-5001D0584217.jpg'],    // two walkers in fog
  ['Lover', '8C6D175D-1848-4C09-86C2-C5FFF725BD9C.webp'],     // silhouette against the tower
  ['Lover', 'DSC00002.webp'],                                 // warm lamp at the bar
  ['Wedding', 'DSC08000-Enhanced-NR.webp'],                   // sunset formal on the hill
]

const CITY_PICKS = [
  ['City', 'E269F072-B91F-4AB0-9EBA-6B0600E08FBD.jpg'],       // tall slot — dusk street, headlights
  ['HK', '20250831_091035.webp'],                             // dense apartment blocks, clouds
  ['HK', '20250831_110334.webp'],                             // taxi under the overpass, night
  ['City', 'IMG_0278.jpeg'],                                  // wide slot — b&w frieze panorama
  ['HK', '20250829_204755.webp'],                             // neon harbour from the window
  ['City', '19AE4761-D63F-4C4C-A77A-7DF33EBE8E25.webp'],      // night grid from the plane
  ['HK', '20250829_173143.webp'],                             // street canyon, big sky
]

const EPI_PICK = ['Wedding', 'DSC08008-Enhanced-NR.webp']     // lakeside dusk wedding table

const dimsByPath = new Map(manifest.photos.map(ph => [ph.path, ph]))

function toEntry(row) {
  const key = normalizePhotoKey(row.path, row.category, row.filename)
  const p = toPublicPath(key)
  const dims = dimsByPath.get(p)
  return {
    p,
    w: dims ? dims.w : null,
    h: dims ? dims.h : null,
    cat: row.category,
    matte: dims ? !!dims.matte : false,
  }
}

async function fetchRows(db) {
  if (db) {
    try {
      const { results } = await db.prepare(
        'SELECT category, filename, path, sort_order, created_at FROM photos'
      ).all()
      if (results && results.length > 0) return results
    } catch (e) {
      console.error('darkroom: D1 query failed, falling back to manifest:', e.message)
    }
  }
  return manifest.photos
}

/** Round-robin interleave grouped lists so the wall mixes categories. */
function interleave(groups) {
  const out = []
  const lists = groups.filter(g => g.length > 0)
  const total = lists.reduce((s, l) => s + l.length, 0)
  let i = 0
  while (out.length < total) {
    for (const list of lists) {
      if (list[i]) out.push(list[i])
    }
    i++
  }
  return out
}

export async function getDarkroomHomeData(db) {
  const rows = await fetchRows(db)

  // category pools, ordered like the category pages (sort_order, filename) —
  // the photographer's own ranking, lowest first.
  const pools = new Map()
  for (const row of rows) {
    const cat = typeof row.category === 'string' ? row.category.trim() : ''
    if (!cat) continue
    if (!pools.has(cat)) pools.set(cat, [])
    pools.get(cat).push(row)
  }
  for (const list of pools.values()) {
    list.sort((a, b) => {
      const sa = a.sort_order ?? Number.MAX_SAFE_INTEGER
      const sb = b.sort_order ?? Number.MAX_SAFE_INTEGER
      if (sa !== sb) return sa - sb
      return String(a.filename).localeCompare(String(b.filename))
    })
  }

  const findByName = (cat, filename) => {
    const row = (pools.get(cat) || []).find(r => r.filename === filename)
    return row ? toEntry(row) : null
  }

  const resolvePicks = picks => {
    const found = picks.map(([cat, f]) => findByName(cat, f)).filter(Boolean)
    return { found, missing: picks.length - found.length }
  }

  /** Top of a category pool, curated picks and white mattes excluded. */
  const takeClean = (cat, n, used) =>
    (pools.get(cat) || [])
      .map(toEntry)
      .filter(e => !e.matte && !(used && used.has(e.p)))
      .slice(0, n)

  const usedPaths = list => new Set(list.map(e => e.p))

  // ——— CH.01 PEOPLE — film strip (portraits lead the whole journey) ———
  const stripRes = resolvePicks(STRIP_PICKS)
  const strip = stripRes.found
  if (stripRes.missing > 0) {
    strip.push(...takeClean('Portrait', stripRes.missing, usedPaths(strip)))
  }
  strip.push(HERO_WIDE)

  // ——— CH.02 CITY — offset grid ———
  const cityRes = resolvePicks(CITY_PICKS)
  let cityGrid = cityRes.found
  if (cityRes.missing > 0) {
    cityGrid.push(...takeClean('HK', cityRes.missing, usedPaths(cityGrid)))
  }
  cityGrid = cityGrid.slice(0, 7)

  // ——— CH.03 WORLD — contact sheet (square crops) ———
  const sheet = [...takeClean('Nature', 10), ...takeClean('Ghibli', 9), ...takeClean('Phone', 5)]

  // ——— CH.04 WALL — every square print with a baked-in white matte ———
  const mattesByCat = new Map()
  for (const ph of manifest.photos) {
    if (!ph.square || !ph.matte) continue
    if (!mattesByCat.has(ph.category)) mattesByCat.set(ph.category, [])
    mattesByCat.get(ph.category).push({ p: ph.path, w: ph.w, h: ph.h, cat: ph.category })
  }
  const wall = interleave([...mattesByCat.values()])

  // ——— epilogue ———
  const epi = findByName(...EPI_PICK) || takeClean('Wedding', 1)[0] || HERO_WIDE

  // ——— INDEX overlay ———
  const knownOrder = CAT_ORDER.filter(c => pools.has(c))
  const extras = [...pools.keys()].filter(c => !CAT_ORDER.includes(c)).sort()
  const cats = [...knownOrder, ...extras].map(name => ({
    name,
    zh: CAT_ZH[name] || name,
    count: (pools.get(name) || []).length,
    href: `/photographer/${name.toLowerCase()}`,
    thumbs: (pools.get(name) || []).slice(0, 4).map(r => toEntry(r).p),
  }))

  const counts = {
    total: rows.length,
    people: ['Portrait', 'Emotion', 'Lover', 'Wedding']
      .reduce((s, c) => s + (pools.get(c) || []).length, 0),
    cats: cats.length,
    wall: wall.length,
  }

  return { hero: HERO_PANELS, strip, cityGrid, sheet, wall, epi, cats, counts }
}
